class Solution:
    def maxConsecutiveAnswers(self, answerKey, k):
        n = len(answerKey)
        best = 0
        for i in range(n):
            cT = cF = 0
            for j in range(i, n):
                if answerKey[j] == 'T':
                    cT += 1
                else:
                    cF += 1
                if min(cT, cF) <= k:
                    best = max(best, j - i + 1)
        return best

