class Solution:
    def maxConsecutiveAnswers(self, answerKey, k):
        def longest(ch):
            left = 0
            count = 0
            best = 0
            for right, c in enumerate(answerKey):
                if c != ch:
                    count += 1
                while count > k:
                    if answerKey[left] != ch:
                        count -= 1
                    left += 1
                best = max(best, right - left + 1)
            return best
        return max(longest('T'), longest('F'))

